display.text:
// ───────────────────────────────────────────────────────────────
// MODULE: Code Graph Indexer Types
// ───────────────────────────────────────────────────────────────
import { createHash } from 'node:crypto';
import { CODE_GRAPH_DEFAULTS } from './config-defaults.js';
import {
  resolveIndexScopePolicy,
  type IndexScopePolicy,
  type ResolveIndexScopePolicyInput,
} from './index-scope-policy.js';

/** Node types extracted by the structural indexer */
export type SymbolKind =
  | 'function' | 'class' | 'method' | 'interface'
  | 'type_alias' | 'variable' | 'enum' | 'module'
  | 'import' | 'export' | 'parameter';

/** Edge types for relationships between symbols */
export type EdgeType =
  | 'CONTAINS' | 'CALLS' | 'IMPORTS' | 'EXPORTS'
  | 'EXTENDS' | 'IMPLEMENTS' | 'TESTED_BY'
  | 'DECORATES' | 'OVERRIDES' | 'TYPE_OF';

export const DEFAULT_EDGE_WEIGHTS: Readonly<Record<EdgeType, number>> = CODE_GRAPH_DEFAULTS.edgeWeights as Readonly<Record<EdgeType, number>>;

/** Honest graph-local detector provenance classes for structural indexing lanes. */
export type DetectorProvenance = 'ast' | 'structured' | 'regex' | 'heuristic';

/** Evidence classes for graph edge payload enrichment. */
export type EdgeEvidenceClass = 'EXTRACTED' | 'INFERRED' | 'AMBIGUOUS';

export interface CodeEdgeMetadata {
  confidence?: number;
  detectorProvenance?: DetectorProvenance;
  evidenceClass?: EdgeEvidenceClass;
  [key: string]: string | number | boolean | null | undefined;
}

/** Languages supported by the structural indexer */
export type SupportedLanguage = 'javascript' | 'typescript' | 'python' | 'bash' | 'doc';

/** A structural symbol node extracted from source code */
export interface CodeNode {
  symbolId: string;
  filePath: string;
  fqName: string;
  kind: SymbolKind;
  name: string;
  startLine: number;
  endLine: number;
  startColumn: number;
  endColumn: number;
  language: SupportedLanguage;
  signature?: string;
  docstring?: string;
  contentHash: string;
}

/** A directional edge between two symbol nodes */
export interface CodeEdge {
  sourceId: string;
  targetId: string;
  edgeType: EdgeType;
  weight: number;
  metadata?: CodeEdgeMetadata;
}

/** Result of parsing a single file */
export interface ParseResult {
  filePath: string;
  language: SupportedLanguage;
  nodes: CodeNode[];
  edges: CodeEdge[];
  detectorProvenance: DetectorProvenance;
  contentHash: string;
  parseHealth: 'clean' | 'recovered' | 'error';
  parseErrors: string[];
  parseDurationMs: number;
}

/** Configuration for the structural indexer */
export interface IndexerConfig {
  rootDir: string;
  includeGlobs: string[];
  excludeGlobs: string[];
  maxFileSizeBytes: number;
  languages: SupportedLanguage[];
  scopePolicy: IndexScopePolicy;
  edgeWeights?: Partial<Record<EdgeType, number>>;
  tsconfigPath?: string;
  baseUrl?: string;
  pathAliases?: {
    prefix: string;
    suffixWildcard: boolean;
    targets: string[];
  }[];
}

/** Generate a deterministic symbol ID from file path, qualified name, and kind */
export function generateSymbolId(filePath: string, fqName: string, kind: SymbolKind): string {
  return createHash('sha256')
    .update(filePath + '::' + fqName + '::' + kind)
    .digest('hex')
    .slice(0, 16);
}

/** Generate a content hash for change detection */
export function generateContentHash(content: string): string {
  return createHash('sha256').update(content).digest('hex').slice(0, 12);
}

/** Detect language from file extension */
export function detectLanguage(filePath: string): SupportedLanguage | null {
  const ext = filePath.split('.').pop()?.toLowerCase();
  switch (ext) {
    case 'js': case 'mjs': case 'cjs': case 'jsx':
      return 'javascript';
    case 'ts': case 'mts': case 'cts': case 'tsx':
      return 'typescript';
    case 'py':
      return 'python';
    case 'sh': case 'bash': case 'zsh':
      return 'bash';
    case 'md': case 'json': case 'jsonc': case 'yaml': case 'yml': case 'toml':
      return 'doc';
    default:
      return null;
  }
}

/** Get default indexer configuration */
export function getDefaultConfig(
  rootDir: string,
  policyInput?: IndexScopePolicy | ResolveIndexScopePolicyInput,
): IndexerConfig {
  const scopePolicy = policyInput && 'fingerprint' in policyInput
    ? policyInput
    : resolveIndexScopePolicy(policyInput);
  // Default scope excludes internal-heavy .opencode folders unless the caller opts in.
  const excludeGlobs = [
    '**/node_modules/**',
    '**/dist/**',
    '**/.git/**',
    '**/vendor/**',
    '**/external/**',
    '**/z_future/**',
    '**/z_archive/**',
    ...scopePolicy.excludedSkillGlobs,
    ...scopePolicy.excludedAgentGlobs,
    ...scopePolicy.excludedCommandGlobs,
    ...scopePolicy.excludedSpecGlobs,
    ...scopePolicy.excludedPluginGlobs,
    ...scopePolicy.excludeGlobs,
  ];

  const defaultIncludeGlobs = [
    '**/*.ts',
    '**/*.tsx',
    '**/*.mts',
    '**/*.cts',
    '**/*.js',
    '**/*.jsx',
    '**/*.mjs',
    '**/*.cjs',
    '**/*.py',
    '**/*.sh',
    '**/*.bash',
    '**/*.zsh',
    // Markdown/prose docs are deliberately NOT indexed: the code graph models code
    // structure and structured config, not documentation. Config formats below still
    // index as `language='doc'` rows. A caller can re-add docs per-scan via includeGlobs.
    '**/*.json',
    '**/*.jsonc',
    '**/*.yaml',
    '**/*.yml',
    '**/*.toml',
  ];

  return {
    rootDir,
    includeGlobs: scopePolicy.includeGlobs.length > 0
      ? [...scopePolicy.includeGlobs]
      : defaultIncludeGlobs,
    excludeGlobs,
    maxFileSizeBytes: 102_400,
    languages: ['javascript', 'typescript', 'python', 'bash', 'doc'],
    scopePolicy,
  };
}

