/** Recursive file finder matching extension from glob pattern */
function findFiles(config: IndexerConfig, pattern: string): FileFindResult {
  const { rootDir, excludeGlobs, maxFileSizeBytes } = config;
  const extMatch = pattern.match(/\*\.(\w+)$/);
  const targetExt = extMatch ? '.' + extMatch[1] : null;
  const results: string[] = [];
  const excludePatterns = excludeGlobs.map(globToRegExp);
  const gitignoreCache = new Map<string, IgnoreInstance | null>();
  let excludedByDefault = 0;
  let excludedByGitignore = 0;
  let visitedNodes = 0;
  let abortedByNodeLimit = false;
  const warnings: string[] = [];
  const capExceeded = { maxNodes: false, depth: false, gitignoreSize: false };

  function walk(currentDir: string, inheritedGitignores: GitignoreContext[], depth: number): void {
    if (abortedByNodeLimit) {
      return;
    }
    if (depth >= FIND_FILES_MAX_DEPTH) {
      const warning = `[structural-indexer] Aborting descent at maxDepth=${FIND_FILES_MAX_DEPTH}: ${currentDir}`;
      console.warn(warning);
      warnings.push(warning);
      capExceeded.depth = true;
      return;
    }

    const localGitignore = loadGitignore(currentDir, gitignoreCache, warnings, capExceeded);
    const activeGitignores = localGitignore
      ? [...inheritedGitignores, { baseDir: currentDir, matcher: localGitignore }]
      : inheritedGitignores;
    let entries;
    try {
      entries = readdirSync(currentDir, { withFileTypes: true });
    } catch { return; }

    for (const entry of entries) {
      visitedNodes += 1;
      if (visitedNodes > FIND_FILES_MAX_NODES) {
        const warning = `[structural-indexer] Aborting walk after ${FIND_FILES_MAX_NODES} filesystem nodes at ${currentDir}`;
        console.warn(warning);
        warnings.push(warning);
        capExceeded.maxNodes = true;
        abortedByNodeLimit = true;
        return;
      }
      const fullPath = resolve(currentDir, entry.name);
      if (shouldExcludePath(rootDir, fullPath, excludePatterns, entry.isDirectory(), config)) {
        excludedByDefault++;
        continue;
      }
      if (isGitignored(fullPath, entry.isDirectory(), activeGitignores)) {
        excludedByGitignore++;
        continue;
      }

      if (entry.isDirectory()) {
        walk(fullPath, activeGitignores, depth + 1);
      } else if (entry.isFile()) {
        if (targetExt && !entry.name.endsWith(targetExt)) continue;
        try {
          const stat = statSync(fullPath);
          if (stat.size <= maxFileSizeBytes) {
            results.push(normalizeFilesystemPath(fullPath));
          } else {
            console.warn(`[structural-indexer] Skipping large file (${(stat.size / 1024).toFixed(1)}KB > ${(maxFileSizeBytes / 1024).toFixed(1)}KB): ${fullPath}`);
          }
        } catch { /* skip */ }
      }
    }
  }

  walk(rootDir, [], 0);
  return { files: results, excludedByDefault, excludedByGitignore, warnings, capExceeded };
}

function collectSpecificFiles(config: IndexerConfig, specificFiles: string[]): string[] {
  const { rootDir, maxFileSizeBytes } = config;
  const dedupedFiles: string[] = [];
  const seenFiles = new Set<string>();
  const canonicalWorkspaceRoot = resolveCanonicalPath(resolve(rootDir));

  for (const filePath of specificFiles) {
    const absolutePath = normalizeFilesystemPath(resolve(filePath));
    const workspaceCandidate = resolveWorkspaceCandidateWithinRoot(absolutePath, canonicalWorkspaceRoot);
    if (!workspaceCandidate || seenFiles.has(workspaceCandidate.canonicalPath)) {
      continue;
    }

    const relativePath = normalizeGlobPath(relative(rootDir, workspaceCandidate.originalPath));
    if (relativePath === '..' || relativePath.startsWith('../')) {
      continue;
    }
    if (!shouldIndexForCodeGraph(workspaceCandidate.canonicalPath, config.scopePolicy)) {
      continue;
    }

    try {
      const stat = statSync(workspaceCandidate.originalPath);
      if (!stat.isFile()) {
        continue;
      }
      if (stat.size > maxFileSizeBytes) {
        console.warn(`[structural-indexer] Skipping large file (${(stat.size / 1024).toFixed(1)}KB > ${(maxFileSizeBytes / 1024).toFixed(1)}KB): ${workspaceCandidate.originalPath}`);
        continue;
      }
    } catch {
      continue;
    }

    seenFiles.add(workspaceCandidate.canonicalPath);
    dedupedFiles.push(workspaceCandidate.originalPath);
  }

  return dedupedFiles;
}

